     1→// DOM rendering and display updates
     2→
     3→import {
     4→    getTileValue,
     5→    isBlocked,
     6→    isBlockedWithLife,
     7→    isBlockedMovable,
     8→    isJoker,
     9→    isCursed,
    10→    isNormal,
    11→    isTileFreeSwapTile,
    12→    isTileStickyFreeSwapTile,
    13→    isTileFreeSwapHorizontalTile,
    14→    isTileFreeSwapVerticalTile,
    15→    isTileHammerTile,
    16→    isTileHalverTile,
    17→    isTileTeleportTile,
    18→    isTilePlusTile,
    19→    isWildTeleportTile,
    20→    getDisplayValue,
    21→    getFontSize,
    22→    isRectangularBlocked,
    23→    findBestJokerValue,
    24→} from "./tile-helpers.js";
    25→import { saveScore, isFeatureUnlocked } from "./storage.js";
    26→import { SUPER_STREAK_THRESHOLD, TILE_TYPE, FEATURE_KEYS } from "./config.js";
    27→
    28→// Helper function to update target values for all joker tiles
    29→function updateJokerTargetValues(game) {
    30→    for (let row = 0; row < game.boardHeight; row++) {
    31→        for (let col = 0; col < game.boardWidth; col++) {
    32→            const tile = game.board[row][col];
    33→            if (isJoker(tile)) {
    34→                // Calculate what value this joker would become if activated
    35→                const targetValue = findBestJokerValue(game, row, col);
    36→                tile.targetValue = targetValue;
    37→            }
    38→        }
    39→    }
    40→}
    41→
    42→function createRectangularBlockedElement(tile) {
    43→    const gem = document.createElement("div");
    44→
    45→    // Set data attributes for identification
    46→    gem.dataset.rectId = tile.rectId;
    47→    gem.dataset.row = tile.rectAnchor.row;
    48→    gem.dataset.col = tile.rectAnchor.col;
    49→    gem.dataset.rectWidth = tile.rectWidth;
    50→    gem.dataset.rectHeight = tile.rectHeight;
    51→
    52→    // CSS Grid positioning (1-indexed)
    53→    const gridRowStart = tile.rectAnchor.row + 1;
    54→    const gridRowEnd = gridRowStart + tile.rectHeight;
    55→    const gridColStart = tile.rectAnchor.col + 1;
    56→    const gridColEnd = gridColStart + tile.rectWidth;
    57→
    58→    gem.style.gridRow = `${gridRowStart} / ${gridRowEnd}`;
    59→    gem.style.gridColumn = `${gridColStart} / ${gridColEnd}`;
    60→
    61→    // Apply appropriate class
    62→    if (tile.type === TILE_TYPE.BLOCKED_WITH_LIFE) {
    63→        gem.className = `gem tile-BLOCKED_WITH_LIFE rectangular-blocked`;
    64→        gem.dataset.life = tile.lifeValue;
    65→    } else if (tile.cellMergeCounts !== undefined) {
    66→        // Blocked tile with merge count (has cellMergeCounts property)
    67→        gem.className = `gem tile-BLOCKED tile-BLOCKED-merge-count rectangular-blocked`;
    68→
    69→        // Set CSS custom properties for grid
    70→        gem.style.setProperty("--rect-width", tile.rectWidth);
    71→        gem.style.setProperty("--rect-height", tile.rectHeight);
    72→
    73→        // Create individual X markers for each cell that needs clearing
    74→        for (let r = 0; r < tile.rectHeight; r++) {
    75→            for (let c = 0; c < tile.rectWidth; c++) {
    76→                const cellRow = tile.rectAnchor.row + r;
    77→                const cellCol = tile.rectAnchor.col + c;
    78→                const cellKey = `${cellRow}_${cellCol}`;
    79→
    80→                // Only render X if cell still needs clearing
    81→                if (tile.cellMergeCounts[cellKey] > 0) {
    82→                    const xMarker = document.createElement("div");
    83→                    xMarker.className = "cell-x-marker";
    84→                    xMarker.dataset.cellKey = cellKey;
    85→                    xMarker.style.gridRow = r + 1;
    86→                    xMarker.style.gridColumn = c + 1;
    87→                    gem.appendChild(xMarker);
    88→                }
    89→            }
    90→        }
    91→    } else {
    92→        gem.className = `gem tile-BLOCKED rectangular-blocked`;
    93→    }
    94→
    95→    return gem;
    96→}
