    98→export function renderBoard(game) {
    99→    const gameBoard = document.getElementById("gameBoard");
   100→    gameBoard.innerHTML = "";
   101→
   102→    // Update CSS grid template to match current board size
   103→    gameBoard.style.gridTemplateColumns = `repeat(${game.boardWidth}, 1fr)`;
   104→    gameBoard.style.gridTemplateRows = `repeat(${game.boardHeight}, 1fr)`;
   105→
   106→    // Calculate width based on board aspect ratio to fit within 50vh height
   107→    // Use visualViewport for zoom-independent dimensions
   108→    const viewport = window.visualViewport || window;
   109→    const aspectRatio = game.boardWidth / game.boardHeight;
   110→    const maxHeight = viewport.height * 0.5; // 50vh of actual visible viewport
   111→    const padding = 30; // Approximate padding from CSS clamp(6px, 3vw, 15px) * 2
   112→    const maxContentHeight = maxHeight - padding;
   113→    const calculatedWidth = maxContentHeight * aspectRatio + padding;
   114→    const maxWidth = Math.min(calculatedWidth, viewport.width * 0.9, 550);
   115→
   116→    gameBoard.style.width = `${maxWidth}px`;
   117→
   118→    // Update target values for all joker tiles before rendering
   119→    updateJokerTargetValues(game);
   120→
   121→    // Track which rectangular blocks have been rendered
   122→    const renderedRectangles = new Set();
   123→
   124→    for (let row = 0; row < game.boardHeight; row++) {
   125→        for (let col = 0; col < game.boardWidth; col++) {
   126→            const tile = game.board[row][col];
   127→
   128→            // NEW: Handle rectangular blocked tiles
   129→            if (isRectangularBlocked(tile)) {
   130→                // Only render once per rectangle
   131→                if (renderedRectangles.has(tile.rectId)) {
   132→                    continue; // Skip other cells of this rectangle
   133→                }
   134→                renderedRectangles.add(tile.rectId);
   135→
   136→                const gem = createRectangularBlockedElement(tile);
   137→                gameBoard.appendChild(gem);
   138→                continue;
   139→            }
   140→
   141→            // EXISTING: Regular tile rendering
   142→            const gem = document.createElement("div");
   143→            gem.dataset.row = row;
   144→            gem.dataset.col = col;
   145→
   146→            // Set CSS class based on tile type
   147→            if (isBlocked(tile)) {
   148→                gem.className = `gem tile-BLOCKED`;
   149→            } else if (isBlockedWithLife(tile)) {
   150→                gem.className = `gem tile-BLOCKED_WITH_LIFE`;
   151→                gem.dataset.life = tile.lifeValue;
   152→            } else if (isBlockedMovable(tile)) {
   153→                gem.className = `gem tile-BLOCKED_MOVABLE`;
   154→            } else if (isJoker(tile)) {
   155→                gem.className = `gem tile-JOKER`;
   156→
   157→                // Calculate what value this joker would become
   158→                let targetValueDisplay = "";
   159→                if (tile.targetValue !== null && tile.targetValue !== undefined) {
   160→                    const displayValue = getDisplayValue(tile.targetValue);
   161→                    const fontSize = getFontSize(displayValue);
   162→                    targetValueDisplay = `<span style="font-size: ${
   163→                        fontSize * 0.7
   164→                    }cqw;" class="preview-value">${displayValue}</span>`;
   165→                }
   166→
   167→                gem.innerHTML = `
   168→                    <span class="star-value" style="">*</span>
   169→                    ${targetValueDisplay}
   170→                `;
   171→                gem.classList.add("joker-tile");
   172→
   173→                // Add wild-teleport class for joker+teleport hybrid tiles
   174→                if (isWildTeleportTile(tile) && !tile.hasBeenSwapped) {
   175→                    gem.classList.add("wild-teleport-tile");
   176→                }
   177→            } else if (isCursed(tile)) {
   178→                const value = getTileValue(tile);
   179→                gem.className = `gem tile-${value} cursed-tile`;
   180→
   181→                const displayValue = getDisplayValue(value);
   182→                gem.innerHTML = `<span style="font-size: ${getFontSize(displayValue)}cqw">${displayValue}</span>`;
   183→
   184→                gem.dataset.cursedMoves = tile.cursedMovesRemaining;
   185→            } else if (isNormal(tile)) {
   186→                const value = getTileValue(tile);
   187→                gem.className = `gem tile-${value}`;
   188→
   189→                const displayValue = getDisplayValue(value);
   190→                gem.innerHTML = `<span style="font-size: ${getFontSize(displayValue)}cqw">${displayValue}</span>`;
   191→
   192→                // Add freeswap-tile class if this is a free swap tile that hasn't been used
   193→                if (isTileFreeSwapTile(tile) && !tile.hasBeenSwapped) {
   194→                    gem.classList.add("freeswap-tile");
   195→                }
   196→
   197→                // Add sticky-freeswap-tile class if this is a sticky free swap tile that hasn't been used
   198→                if (isTileStickyFreeSwapTile(tile) && !tile.hasBeenSwapped) {
   199→                    gem.classList.add("sticky-freeswap-tile");
   200→                }
   201→
   202→                // Add directional free swap classes
   203→                if (isTileFreeSwapHorizontalTile(tile) && !tile.hasBeenSwapped) {
   204→                    gem.classList.add("freeswap-horizontal-tile");
   205→                }
   206→
   207→                if (isTileFreeSwapVerticalTile(tile) && !tile.hasBeenSwapped) {
   208→                    gem.classList.add("freeswap-vertical-tile");
   209→                }
   210→
   211→                // Add hammer-tile class if this is a hammer tile
   212→                if (isTileHammerTile(tile)) {
   213→                    gem.classList.add("hammer-tile");
   214→                }
   215→
   216→                // Add halver-tile class if this is a halver tile
   217→                if (isTileHalverTile(tile)) {
   218→                    gem.classList.add("halver-tile");
   219→                }
   220→
   221→                // Add teleport-tile class if this is a teleport tile
   222→                if (isTileTeleportTile(tile)) {
   223→                    gem.classList.add("teleport-tile");
   224→                    // Add teleport-used class if the tile has already been swapped
   225→                    if (tile.hasBeenSwapped) {
   226→                        gem.classList.add("teleport-used");
   227→                    }
   228→                }
   229→
   230→                // Add plus-tile class if this is a plus tile
   231→                if (isTilePlusTile(tile)) {
   232→                    gem.classList.add("plus-tile");
   233→                }
   234→            }
   235→
   236→            gameBoard.appendChild(gem);
   237→        }
   238→    }
   239→
   240→    // Restore preview classes for pending interrupt swap
   241→    if (game.pendingSwap) {
   242→        const { row1, col1, row2, col2, tile1, tile2 } = game.pendingSwap;
   243→
   244→        const tilesUnchanged = game.board[row1][col1] === tile1 && game.board[row2][col2] === tile2;
   245→        if (tilesUnchanged) {
   246→            const gem1 = document.querySelector(`[data-row="${row1}"][data-col="${col1}"]`);
   247→            const gem2 = document.querySelector(`[data-row="${row2}"][data-col="${col2}"]`);
   248→            if (gem1) gem1.classList.add("pending-preview");
   249→            if (gem2) gem2.classList.add("pending-preview");
   250→        } else {
   251→            game.interruptCascade = false;
   252→            game.pendingSwap = null;
   253→        }
   254→    }
   255→
   256→    updateGoalDisplay(game);
   257→
   258→    // Restore hint highlight if active
   259→    if (game.currentHint) {
   260→        renderHintHighlight(game);
   261→    }
   262→}
   263→
   264→export function renderHintHighlight(game) {
   265→    if (!game.currentHint) return;
   266→
   267→    const gem1 = document.querySelector(
   268→        `[data-row="${game.currentHint.row1}"][data-col="${game.currentHint.col1}"]`,
   269→    );
   270→    const gem2 = document.querySelector(
   271→        `[data-row="${game.currentHint.row2}"][data-col="${game.currentHint.col2}"]`,
   272→    );
   273→
   274→    if (gem1 && game.currentHint.direction1) {
   275→        gem1.classList.add(`hint-nudge-${game.currentHint.direction1}`);
   276→    }
   277→    if (gem2 && game.currentHint.direction2) {
   278→        gem2.classList.add(`hint-nudge-${game.currentHint.direction2}`);
   279→    }
   280→
   281→    if (game.currentHint.matchTiles) {
   282→        for (const tile of game.currentHint.matchTiles) {
   283→            const matchGem = document.querySelector(`[data-row="${tile.row}"][data-col="${tile.col}"]`);
   284→            matchGem?.classList.add("hint-merge-preview");
   285→        }
   286→    }
   287→}
