   392→export function renderPowerUpRewards(game) {
   393→    const container = document.getElementById("powerUpRewardsContainer");
   394→    const hammerTiles = document.getElementById("hammerRewardTiles");
   395→    const halveTiles = document.getElementById("halveRewardTiles");
   396→    const swapTiles = document.getElementById("swapRewardTiles");
   397→
   398→    if (!container || !hammerTiles || !halveTiles || !swapTiles) return;
   399→
   400→    const rewards = game.levelConfig.powerUpRewards;
   401→    if (!rewards || rewards.length === 0) {
   402→        container.style.display = "none";
   403→        return;
   404→    }
   405→
   406→    container.style.display = "flex";
   407→
   408→    // Clear all columns
   409→    hammerTiles.innerHTML = "";
   410→    halveTiles.innerHTML = "";
   411→    swapTiles.innerHTML = "";
   412→
   413→    // Sort rewards and distribute to columns based on cycling order
   414→    const sortedRewards = [...rewards].sort((a, b) => a - b);
   415→    const columns = [hammerTiles, halveTiles, swapTiles];
   416→
   417→    sortedRewards.forEach((tileValue, index) => {
   418→        const isCompleted = game.completedPowerUpRewards.includes(tileValue);
   419→        const displayValue = getDisplayValue(tileValue);
   420→        const columnIndex = index % 3;
   421→
   422→        const tile = document.createElement("div");
   423→        tile.className = `gem tile-${tileValue} powerup-reward-tile ${isCompleted ? "completed" : ""}`;
   424→        tile.innerHTML = `<span style="font-size: ${getFontSize(displayValue)}cqw">${displayValue}</span>`;
   425→
   426→        columns[columnIndex].appendChild(tile);
   427→    });
   428→}
