   430→export function renderBoardUpgrades(game) {
   431→    const upgradesContainer = document.getElementById("boardUpgradesContainer");
   432→    const upgradesElement = document.getElementById("boardUpgrades");
   433→    const upgradeIcon = upgradesContainer?.querySelector(".upgrade-icon");
   434→    if (!upgradesContainer || !upgradesElement) return;
   435→
   436→    const levelConfig = game.levelConfig;
   437→
   438→    // Only show if level has boardUpgrades configured
   439→    if (!levelConfig.boardUpgrades || levelConfig.boardUpgrades.length === 0) {
   440→        upgradesContainer.style.display = "none";
   441→        return;
   442→    }
   443→
   444→    upgradesContainer.style.display = "flex";
   445→    upgradesElement.innerHTML = "";
   446→
   447→    // Update icon based on super streak status
   448→    if (upgradeIcon) {
   449→        if (game.superStreak >= SUPER_STREAK_THRESHOLD) {
   450→            upgradeIcon.src = "assets/upgrade-icon_streak.png";
   451→            upgradeIcon.classList.add("active");
   452→        } else {
   453→            upgradeIcon.src = "assets/upgrade-icon.png";
   454→            upgradeIcon.classList.remove("active");
   455→        }
   456→    }
   457→
   458→    // Show upgrade trigger tiles stacked vertically
   459→    levelConfig.boardUpgrades
   460→        .sort((a, b) => b - a)
   461→        .forEach((tileValue) => {
   462→            const isCompleted = game.completedUpgrades.includes(tileValue);
   463→            const displayValue = getDisplayValue(tileValue);
   464→
   465→            const upgradeTile = document.createElement("div");
   466→            upgradeTile.className = `gem tile-${tileValue} upgrade-tile ${isCompleted ? "completed" : ""}`;
   467→            upgradeTile.innerHTML = `<span style="font-size: ${getFontSize(displayValue)}cqw">${displayValue}</span>`;
   468→
   469→            upgradesElement.appendChild(upgradeTile);
   470→        });
   471→}
