.game-board.level-ended {
    opacity: 0.5;
}

.gem {
    aspect-ratio: 1;
    border-radius: 20%;
    cursor: pointer;
    position: relative;
    transition:
        transform 0.3s ease,
        opacity 0.3s ease,
        background-color 0.3s ease,
        box-shadow 0.3s ease,
        filter 0.3s ease,
        outline-color 0.3s ease;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 -3px 0 0 rgba(0, 0, 0, 0.25) inset;
    font-family: Nunito;
    font-size: clamp(16px, 3vw, 24px);
    font-weight: 900;
    color: #45413d;
    container-type: inline-size;
    container-name: card;
    padding-bottom: 2px;
    outline-color: rgba(0, 0, 0, 0);

    -webkit-tap-highlight-color: transparent;
}

.gem > * {
    pointer-events: none;
}

.gem.swap-dimmed {
    opacity: 0.6;
    filter: grayscale(0.2);
    pointer-events: none;
}

.gem.dragging {
    z-index: 10;
    /* opacity: 0.7; */
    /* transform: scale(0.95); */
    transform: scale(1.1);
    /* box-shadow: 0 8px 16px rgba(0, 0, 0, 0.3); */
}

.gem.preview,
